var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"역시, 이 소년은 아직이군.","JPN":"やはり、この少年はまだまだだ。","ENG":"As expected, the boy isn’t good enough.","TWN":"你的實力果然還是不夠啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"기량만큼은 높이 쳐 줄 수 있지만, 힘도 경험도 발키리에 비하면 부족해.","JPN":"技量は高く評価できるが、力も経験もヴァルキリーほどではない。","ENG":"I acknowledge your talent, but your strength and experience are far behind the Valkyrie's.","TWN":"雖然很有才能，但力量和經驗都和女武神差遠了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그런데 어째서…….","JPN":"なのにどうしてだ……","ENG":"But why…","TWN":"不過為什麼……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"어째서 꺾이지 않는 거지……?","JPN":"どうして挫けない……？","ENG":"Why won't you give up...?","TWN":"為什麼打不倒你呢……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"흐음, 역시…….","JPN":"ふむ、やはり……","ENG":"Hmm, as I thought...","TWN":"咳呃，這說明……我所預料的是對的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"제가 얻은 깨달음을 그대로 따를 뿐입니다. 별거 아니에요.","JPN":"僕は悟りにそのまま従うまでです。特別なことではありませんよ。","ENG":"I simply go by the lesson I learned. It’s nothing special.","TWN":"我只是按著我的領悟而已，並沒有什麼特別的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"삶과 죽음도 하나일진대, 가진 것과 버린 것이 무슨 차이가 있겠습니까?","JPN":"生きるも死ぬも裏表、持つも持たないも同じでしょう。","ENG":"If life and death are two sides of the same coin, what difference is there in what I own and what I don't?","TWN":"生和死也是一體的，擁有和放棄又有什麼區別呢？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"태산 같은 힘이라도 흘러가는 대로 받아들이는 거죠.","JPN":"とてつもない大きな力もまた、受け入れてしまうんです。","ENG":"Even with immense power like this, I simply let it flow through.","TWN":"就算是泰山般的力量，我也會順其自然地接受。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"……갈대 흉내라도 내겠다는 건가?","JPN":"……葦を真似ようとでもしてるのか？","ENG":"…You just wish to go with the flow?","TWN":"……這麼說，你是蘆葦嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그렇다면 좋다. 쓰러지지 않는 갈대는 불태워 버리면 그만이지.","JPN":"ならばかまわない。倒れない葦は燃やしてしまえばよい。","ENG":"Very well. I shall stop the flow completely then.","TWN":"那好。不倒的蘆葦只要燒了就好。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"세상이 끝나는 날까지, 천만 번이라도 죽여 보이마.","JPN":"世界が終わるその日まで、幾度でも殺してみせよう。","ENG":"I will kill you over and over again, until the world ends.","TWN":"我要殺你千萬次，直到世界末日來臨。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"음……?! 방금 그 반격은…….","JPN":"ん……！？　今のその反撃は？","ENG":"Mm…?! That counterattack just now…","TWN":"嗯……？！剛才的反擊是……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"네 놈, 무슨 수작을 부린 거냐?","JPN":"貴様、何をした？","ENG":"You. What did you just do?","TWN":"小夥子，你究竟在耍什麼花招？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"전하가 무절제하게 흘려 보내는 힘을 살짝 활용했을 뿐입니다.","JPN":"殿下が際限なしに放つ力を、少し利用したまでです。","ENG":"All I did was utilize a portion of your uncontrollable power coming my way.","TWN":"我只是利用了一下殿下你毫無節制地輸出的力量而已。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"헛소리 마라. 방금 그 힘에는 분명히 용혈의 기운이 느껴졌다.","JPN":"ふざけるな。今の力には確かに龍血の力を感じた。","ENG":"Nonsense. I felt Dragon Blood just now.","TWN":"別胡說，我明明在剛才的那股力量中感受到了龍血的氣息。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그러게요. 이를 어쩌죠?","JPN":"そうですね。どうしましょう？","ENG":"It seems to be the case. What to do now?","TWN":"是啊，這可怎麼辦呢？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"전하께서 애지중지하시는 용혈은, 저와 더 상성이 잘 맞는다고 하는 것 같은데요.","JPN":"殿下がそれほど大事にする龍血は、僕との方が相性が良いらしいです。","ENG":"It seems that your beloved Dragon Blood suits me better than you.","TWN":"殿下所珍愛的龍血，好像和我更配呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"설마…. 용혈을 포기하면서 비워지게 된 몸에 반응한다고?","JPN":"まさか……龍血を放棄したことで空になった身体に反応するだと？","ENG":"It can't be… It reacts to an emptied vessel that abandoned Dragon Blood?","TWN":"難道……對放棄龍血後空出來的身體有反應？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"스스로 포기했음에도 여전히 네가 용혈의 정당한 주인이란 말인가? 라르고의 통제를 벗어날 정도로?","JPN":"自ら手放しておいてなお、龍血の正当な主人は貴様だということか？　ラルゴの統制を破るほどに？","ENG":"Are you still the rightful owner of Dragon Blood, even after giving it up? Suited enough to ignore the Largo's control?","TWN":"你明明自己放棄了，卻還是龍血的正當主人嗎？甚至可以擺脫雷諾可的控制？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"……전하께서는 확실히 강한 분이십니다.","JPN":"……殿下は確かに強いお方です。","ENG":"...Your Highness. You are strong, which I cannot deny.","TWN":"……殿下確實是個強者。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"솔직히, 남겠다고 하면서도 감당할 수 있을지 반신반의했거든요.","JPN":"正直、自分でもここに残ると言いながら、殿下を止められるのか、半信半疑でしたからね。","ENG":"Frankly speaking, I wasn't sure if I could handle fighting you even though I volunteered.","TWN":"說實話，雖然我主動說要留在這裡，但對於能否戰勝殿下其實是沒有把握的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 하지만 상성이 나쁜 걸 어떡하겠어요?","JPN":"はは、でも相性が悪いのは仕方がないですよね？","ENG":"Ha ha, But it can't be helped. Advantages, you see.","TWN":"哈哈，不過有些事情就是無法控制的，我能怎麼辦呢？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"한낱 핏방울도 사사건건 고삐를 쥐려는 주인보단 있는 그대로 내버려 두는 주인이 좋은 거겠죠.","JPN":"ただの血も、ことあるごとにコントロールしようとする主人より、ありのままにほっといてくれる主人の方が良いのでしょう。","ENG":"Even for something as simple as blood, they prefer an owner who would let them be rather than an owner who puts them on a leash.","TWN":"比起連一滴血都要緊緊抓在手裡的主人，當然還是聽之任之的主人更好吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"네 놈…… 감히 그런 어설픈 각오로 내 앞을 막아섰다는 거냐?","JPN":"貴様……そんな中途半端な覚悟で私を止めようというのか？","ENG":"You dare... You dare confront me with that sloppy attitude?","TWN":"你這傢伙……竟敢以這種膚淺的覺悟擋在我面前？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"말씀드렸지 않습니까. 삶과 죽음도 하나일진대.","JPN":"言ったじゃないですか。生きるも死ぬも裏表だと。","ENG":"As I said, life and death are of the same.","TWN":"我不是說過了嗎，生和死也是一體的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그리고…… 저는 제가 틀렸더라도 걱정은 없거든요.","JPN":"それに……僕は自分が間違っていたとしても不安にはなりませんよ。","ENG":"And besides... I wouldn't be concerned even if I were wrong.","TWN":"還有……即使我錯了，我也不擔心。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"스승님도, 미나 양도. 각자 잘해 주실 테니까요.","JPN":"師匠も、ミナさんも、皆さんフォローしてくれますから。","ENG":"I know that Master and Mina would do well.","TWN":"因為師父，還有米娜，都會做好各自的事情。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"인정하지. 발키리 대신 너를 먼저 제거하지 않은 것은 크나큰 실책이었다.","JPN":"認めよう。ヴァルキリーではなく、貴様を先に始末しなかったことは大きな失策だった。","ENG":"I admit it. It was a fatal mistake to not eliminate you, instead of the Valkyrie.","TWN":"我承認。沒有代替女武神先除掉你是我的巨大失誤。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그러니…… 여기서 만회하도록 하지.","JPN":"だから……ここで挽回させてもらおう。","ENG":"Which is why... I will make up for that.","TWN":"所以……我就在這裡彌補吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"몇 번이고 시도해 보시죠.","JPN":"何度でも試してみてください。","ENG":"You can try as many times as you want.","TWN":"那你最好再多嘗試幾次吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그리 쉽지는 않겠지만요.","JPN":"そう簡単にはいかないと思いますけどね。","ENG":"Although it won't be that easy.","TWN":"不會那麼容易的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};